-- ============================================================
-- PostgreSQL Schema + Seed Data — HR Management System
-- Generated from db.json
-- ============================================================

CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- ============================================================
-- TEARDOWN
-- ============================================================

DROP TABLE IF EXISTS notification_preferences CASCADE;
DROP TABLE IF EXISTS notifications           CASCADE;
DROP TABLE IF EXISTS password_resets         CASCADE;
DROP TABLE IF EXISTS announcements           CASCADE;
DROP TABLE IF EXISTS qualifications          CASCADE;
DROP TABLE IF EXISTS employment_history      CASCADE;
DROP TABLE IF EXISTS documents               CASCADE;
DROP TABLE IF EXISTS staff_responsibilities  CASCADE;
DROP TABLE IF EXISTS responsibilities        CASCADE;
DROP TABLE IF EXISTS committee_members       CASCADE;
DROP TABLE IF EXISTS committees              CASCADE;
DROP TABLE IF EXISTS nature_of_appointments  CASCADE;
DROP TABLE IF EXISTS system_preferences      CASCADE;
DROP TABLE IF EXISTS payrolls                CASCADE;
DROP TABLE IF EXISTS attendance              CASCADE;
DROP TABLE IF EXISTS leaves                  CASCADE;
DROP TABLE IF EXISTS leave_types             CASCADE;
DROP TABLE IF EXISTS users                   CASCADE;
DROP TABLE IF EXISTS staff                   CASCADE;
DROP TABLE IF EXISTS ranks                   CASCADE;
DROP TABLE IF EXISTS departments             CASCADE;
DROP TABLE IF EXISTS roles                   CASCADE;

DROP TYPE IF EXISTS staff_status      CASCADE;
DROP TYPE IF EXISTS gender_type       CASCADE;
DROP TYPE IF EXISTS cadre_type        CASCADE;
DROP TYPE IF EXISTS staff_category    CASCADE;
DROP TYPE IF EXISTS leave_status      CASCADE;
DROP TYPE IF EXISTS degree_type       CASCADE;
DROP TYPE IF EXISTS study_mode        CASCADE;
DROP TYPE IF EXISTS sponsorship_type  CASCADE;
DROP TYPE IF EXISTS leave_category    CASCADE;
DROP TYPE IF EXISTS pay_status        CASCADE;
DROP TYPE IF EXISTS att_status        CASCADE;
DROP TYPE IF EXISTS payroll_status    CASCADE;
DROP TYPE IF EXISTS notif_type        CASCADE;
DROP TYPE IF EXISTS notif_priority    CASCADE;
DROP TYPE IF EXISTS user_role         CASCADE;
DROP TYPE IF EXISTS responsibility_priority CASCADE;
DROP TYPE IF EXISTS date_format_type  CASCADE;
DROP TYPE IF EXISTS fiscal_month_type CASCADE;
DROP TYPE IF EXISTS theme_type        CASCADE;

-- ============================================================
-- ENUMS
-- ============================================================

CREATE TYPE staff_status      AS ENUM ('Employed','On Leave','Retired','Resigned','Terminated','Contract Ended');
CREATE TYPE gender_type       AS ENUM ('Male','Female','Other');
-- Fixed: was 'dept_administrative' (typo), now matches Prisma Cadre enum
CREATE TYPE cadre_type        AS ENUM ('Teaching','Non-Teaching','Technical','Administrative');
CREATE TYPE staff_category    AS ENUM ('Senior','Junior');
CREATE TYPE leave_status      AS ENUM ('PENDING','APPROVED','REJECTED','CANCELLED');

-- ── Study leave sub-types (back TLeaveStudyDetails JSONB validation) ──────
CREATE TYPE degree_type       AS ENUM ('PHD','MSC','PGD','BSC');
CREATE TYPE study_mode        AS ENUM ('FULL_TIME','PART_TIME');
CREATE TYPE sponsorship_type  AS ENUM ('Self','StateGovernment','UniversityBase','TedFund','Others');
CREATE TYPE leave_category    AS ENUM ('Study','Medical','Maternity','Paternity','Other');
CREATE TYPE pay_status        AS ENUM ('WithPayment','WithoutPayment');

CREATE TYPE att_status        AS ENUM ('PRESENT','ABSENT','HALF_DAY','LATE','ON_LEAVE','WEEKEND','HOLIDAY');
CREATE TYPE payroll_status    AS ENUM ('DRAFT','PROCESSED','PAID');
CREATE TYPE notif_type        AS ENUM ('leave_approved','leave_rejected','leave_pending','payroll','contract','system','profile','attendance','general');
CREATE TYPE notif_priority    AS ENUM ('low','medium','high','urgent');
-- Fixed: was ('dept_admin','staff','dept_admin') — duplicate, missing hr_admin
CREATE TYPE user_role         AS ENUM ('hr_admin','dept_admin','staff');
CREATE TYPE responsibility_priority AS ENUM ('low','medium','high');
CREATE TYPE date_format_type  AS ENUM ('DD/MM/YYYY','MM/DD/YYYY','YYYY-MM-DD');
CREATE TYPE fiscal_month_type AS ENUM ('January','February','March','April','May','June','July','August','September','October','November','December');
CREATE TYPE theme_type        AS ENUM ('light','dark','system');

-- ============================================================
-- ROLES
-- Permission reference table — maps to UserRole enum values.
-- permissions is a JSONB array of action strings e.g.
-- ["leave:approve","staff:read","payroll:process"]
-- ============================================================

CREATE TABLE roles (
    id           TEXT        PRIMARY KEY DEFAULT gen_random_uuid()::TEXT,
    name         TEXT        NOT NULL UNIQUE,  -- matches user_role enum
    display_name TEXT        NOT NULL,
    description  TEXT,
    permissions  JSONB       NOT NULL DEFAULT '[]',
    is_active    BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

    'hr_admin',
    'HR Administrator',
    'Full system access — manages staff, leave, payroll, and system settings.',
    '["staff:*","leave:*","payroll:*","attendance:*","document:*","notification:*","committee:*","announcement:*","report:*","settings:*"]'::jsonb
  ),
  (
    'dept_admin',
    'Department Administrator',
    'Manages leave requests and staff within their own department.',
    '["staff:read","staff:update","leave:read","leave:approve","leave:reject","attendance:read","document:read","announcement:read","notification:read"]'::jsonb
  ),
  (
    'staff',
    'Staff',
    'Basic access — can view own profile, apply for leave, and view own attendance.',
    '["leave:apply","leave:read:own","attendance:read:own","document:read:own","notification:read:own","profile:update:own"]'::jsonb
  );

-- ============================================================
-- DEPARTMENTS
-- ============================================================

CREATE TABLE departments (
    id          TEXT        PRIMARY KEY,
    name        TEXT        NOT NULL,
    code        TEXT        NOT NULL UNIQUE,
    description TEXT,
    head_id     TEXT,
    is_active   BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- RANKS
-- ============================================================

CREATE TABLE ranks (
    id           TEXT        PRIMARY KEY,
    title        TEXT        NOT NULL,
    level        INT         NOT NULL,
    description  TEXT,
    -- salary_grade TEXT,
    -- is_active    BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- STAFF
-- ============================================================

CREATE TABLE staff (
    id                        TEXT           PRIMARY KEY,
    staff_no                  TEXT           NOT NULL UNIQUE,
    title                     TEXT,
    first_name                TEXT           NOT NULL,
    last_name                 TEXT           NOT NULL DEFAULT '',
    email                     TEXT           NOT NULL UNIQUE,
    phone                     TEXT,
    date_of_birth             DATE,
    gender                    gender_type,
    address                   TEXT,
    city                      TEXT,
    state                     TEXT,
    lga                       TEXT,
    department_id             TEXT           REFERENCES departments(id),
    rank_id                   TEXT           REFERENCES ranks(id),
    rank                      TEXT,
    cadre                     cadre_type     NOT NULL,
    staff_category            staff_category NOT NULL,
    marital_status            TEXT,
    religion                  TEXT,
    profile_photo             TEXT,
    nature_of_appointment     TEXT,
    conuass_contiss           TEXT,
    date_of_first_appointment DATE,
    date_of_last_promotion    DATE,
    status                    staff_status   NOT NULL DEFAULT 'Employed',
    created_at                TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
    updated_at                TIMESTAMPTZ    NOT NULL DEFAULT NOW()
);

-- ============================================================
-- USERS
-- ============================================================

CREATE TABLE users (
    id            TEXT        PRIMARY KEY,
    email         TEXT        NOT NULL UNIQUE,
    password_hash TEXT        NOT NULL,
    first_name    TEXT        NOT NULL,
    last_name     TEXT        NOT NULL DEFAULT '',
    role          user_role   NOT NULL DEFAULT 'staff',
    staff_id      TEXT        UNIQUE REFERENCES staff(id),
    department_id TEXT        REFERENCES departments(id),
    profile_photo TEXT,
    phone_number  TEXT,
    is_active     BOOLEAN     NOT NULL DEFAULT TRUE,
    last_login    TIMESTAMPTZ,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- LEAVE TYPES
-- ============================================================

CREATE TABLE leave_types (
    id                TEXT        PRIMARY KEY,
    name              TEXT        NOT NULL UNIQUE,
    allowed_days      INT         NOT NULL,
    carry_forward     BOOLEAN     NOT NULL DEFAULT FALSE,
    max_carry_forward INT         NOT NULL DEFAULT 0,
    paid_leave        BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- LEAVE REQUESTS
-- ============================================================

CREATE TABLE leaves (
    id                   TEXT         PRIMARY KEY,
    staff_id             TEXT         NOT NULL REFERENCES staff(id),
    leave_type_id        TEXT         NOT NULL REFERENCES leave_types(id),
    start_date           DATE         NOT NULL,
    end_date             DATE         NOT NULL,
    total_days           INT          NOT NULL,
    reason               TEXT,
    status               leave_status NOT NULL DEFAULT 'PENDING',
    approver_id          TEXT         REFERENCES staff(id),
    approver_comments    TEXT,
    -- JSONB storing TLeaveStudyDetails — only populated for study/extended leaves.
    -- Shape: { institution, programme, degreeType, studyMode, durationYear,
    --          country, sponsorshipType, leaveCategory, payStatus, guarantor_NextOfKin }
    -- Kept as JSONB (not a separate table) because it is an optional sub-document
    -- that is only relevant for a small subset of leave types. This avoids a wide
    -- nullable-column table while still being fully queryable with ->>/-> operators.
    study_leave_details  JSONB,
    applied_at           TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    responded_at         TIMESTAMPTZ,
    created_at           TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    updated_at           TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

-- Index: fast JSONB queries on study_leave_details fields
-- e.g.  WHERE study_leave_details->>'leaveCategory' = 'Study'
CREATE INDEX idx_leaves_study_details
    ON leaves USING GIN (study_leave_details jsonb_path_ops)
    WHERE study_leave_details IS NOT NULL;

-- Constraint: if study_leave_details is present it must be a JSON object (not array/scalar)
ALTER TABLE leaves
    ADD CONSTRAINT chk_study_leave_details_is_object
    CHECK (study_leave_details IS NULL OR jsonb_typeof(study_leave_details) = 'object');

-- ============================================================
-- ATTENDANCE
-- ============================================================

CREATE TABLE attendance (
    id          TEXT        PRIMARY KEY,
    staff_id    TEXT        NOT NULL REFERENCES staff(id),
    date        DATE        NOT NULL,
    check_in    TIMESTAMPTZ,
    check_out   TIMESTAMPTZ,
    work_hours  NUMERIC(4,2),
    status      att_status  NOT NULL,
    remarks     TEXT,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (staff_id, date)
);

-- ============================================================
-- PAYROLLS
-- ============================================================

CREATE TABLE payrolls (
    id               TEXT           PRIMARY KEY,
    staff_id         TEXT           NOT NULL REFERENCES staff(id),
    month            DATE           NOT NULL,
    month_label      TEXT,
    basic_salary     NUMERIC(15,2)  NOT NULL,
    allowances       JSONB          NOT NULL DEFAULT '{}',
    total_allowances NUMERIC(15,2)  NOT NULL,
    gross_salary     NUMERIC(15,2)  NOT NULL,
    deductions       JSONB          NOT NULL DEFAULT '{}',
    total_deductions NUMERIC(15,2)  NOT NULL,
    net_salary       NUMERIC(15,2)  NOT NULL,
    status           payroll_status NOT NULL DEFAULT 'DRAFT',
    payment_date     DATE,
    created_at       TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
    updated_at       TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
    UNIQUE (staff_id, month)
);

-- ============================================================
-- QUALIFICATIONS
-- ============================================================

CREATE TABLE qualifications (
    id          TEXT        PRIMARY KEY,
    staff_id    TEXT        NOT NULL REFERENCES staff(id) ON DELETE CASCADE,
    degree      TEXT        NOT NULL,
    institution TEXT        NOT NULL,
    year        TEXT,
    level       TEXT,
    is_highest  BOOLEAN     NOT NULL DEFAULT FALSE,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- ANNOUNCEMENTS
-- ============================================================

CREATE TABLE announcements (
    id           TEXT        PRIMARY KEY,
    title        TEXT        NOT NULL,
    content      TEXT        NOT NULL,
    priority     TEXT        NOT NULL DEFAULT 'normal',
    published_by TEXT        REFERENCES staff(id),   -- stores staff_id, not user_id
    published_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    expires_at   TIMESTAMPTZ,
    created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- NOTIFICATIONS
-- ============================================================

CREATE TABLE notifications (
    id         TEXT           PRIMARY KEY,
    user_id    TEXT           NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    type       notif_type     NOT NULL,
    title      TEXT           NOT NULL,
    message    TEXT           NOT NULL,
    priority   notif_priority NOT NULL DEFAULT 'low',
    read       BOOLEAN        NOT NULL DEFAULT FALSE,
    icon       TEXT,
    action_url TEXT,
    metadata   JSONB          NOT NULL DEFAULT '{}',
    created_at TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
    read_at    TIMESTAMPTZ
);

-- ============================================================
-- INDEXES
-- ============================================================

CREATE INDEX idx_staff_department ON staff(department_id);
CREATE INDEX idx_staff_rank       ON staff(rank_id);
CREATE INDEX idx_staff_status     ON staff(status);
CREATE INDEX idx_staff_cadre      ON staff(cadre);
CREATE INDEX idx_leave_staff      ON leaves(staff_id);
CREATE INDEX idx_leave_status     ON leaves(status);
CREATE INDEX idx_attendance_date  ON attendance(date);
CREATE INDEX idx_payroll_month    ON payrolls(month);
CREATE INDEX idx_payroll_staff    ON payrolls(staff_id);
CREATE INDEX idx_notif_user       ON notifications(user_id);
CREATE INDEX idx_notif_read       ON notifications(read);
CREATE INDEX idx_qual_staff       ON qualifications(staff_id);

ALTER TABLE departments ADD CONSTRAINT fk_dept_head
    FOREIGN KEY (head_id) REFERENCES staff(id) DEFERRABLE INITIALLY DEFERRED;

